#define MODEL_OUTPUT_LONG_NUMBER_T float

// node 0 is InputLayer so use its output shape as input shape of the model
// typedef  input_t[186][9];
typedef float input_t[186][9];
typedef classifier_output_type output_t;


void cnn(
  const input_t input,
  output_t output);

